package net.minecraft.network.play.client;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayServer;
import java.io.IOException;

public class C0CPacketInput implements Packet<INetHandlerPlayServer> {
    private float sideways;
    private float forward;
    private boolean jump;
    private boolean unmount;

    public C0CPacketInput() {}

    public C0CPacketInput(float sidewaysIn, float forwardIn,
                          boolean jumpIn, boolean unmountIn) {
        this.sideways = sidewaysIn;
        this.forward = forwardIn;
        this.jump = jumpIn;
        this.unmount = unmountIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.sideways = buf.readFloat();
        this.forward = buf.readFloat();
        this.jump = buf.readBoolean();
        this.unmount = buf.readBoolean();
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        buf.writeFloat(this.sideways);
        buf.writeFloat(this.forward);
        buf.writeBoolean(this.jump);
        buf.writeBoolean(this.unmount);
    }

    public void processPacket(INetHandlerPlayServer handler) {
        handler.processInput(this);
    }

    public float getSideways() { return this.sideways; }
    public float getForward() { return this.forward; }
    public boolean isJump() { return this.jump; }
    public boolean isUnmount() { return this.unmount; }
}

